int main() {
    std::string line;
    std::getline(std::cin, line);
    size_t initial_size = std::stoul(line);

    { // Scope 1 to control object lifetimes
        ResourceHandler h1(initial_size);
        h1.print_data();
        if (initial_size > 0) h1.set_element(0, 10);

        ResourceHandler h2 = h1; // Copy construction
        if (initial_size > 0) h2.set_element(1, 11);
        h2.print_data();

        ResourceHandler h3(5);
        h3.print_data();
        h3 = std::move(h1); // Move assignment
        h3.print_data();

        ResourceHandler h4(2);
        ResourceHandler h5 = std::move(h4); // Move construction
        h5.print_data();

    } // h5, h4, h3, h2, h1 are destroyed in reverse order of declaration

    return 0;
}
